import React from 'react';
import { Link } from 'react-router-dom';
import { FaStethoscope } from 'react-icons/fa';

const Navbar = () => {
  return (
    <nav className="fixed top-0 left-0 right-0 bg-white shadow-lg z-50 border-b-2 border-primary-light">
      <div className="container mx-auto px-6">
        <div className="flex items-center h-16">
          {/* Logo - Stethoscope Icon Only */}
          <Link 
            to="/" 
            className="flex items-center gap-3 text-primary-color hover:text-primary-dark transition-colors duration-200 focus-ring"
            aria-label="Go to homepage"
          >
            <FaStethoscope className="text-3xl" />
          </Link>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
